blocks.body:
{
    "level": "A1–A2",
    "intro": "W tym temacie dowiesz się <strong>imperatywów</strong> (imperatywów): jak wydawać polecenia, prośby, rady i instrukcje w języku angielskim.",
    "rules": [
        {
            "label": "Twierdzące",
            "color": "emerald",
            "text": "<strong>Twierdzące forma</strong> — zaczyna się od czasowników:",
            "example": "Usiądź. / Otwórz drzwi."
        },
        {
            "label": "Przeczenie",
            "color": "rose",
            "text": "<strong>Forma przeczenia</strong> — Nie + czasownik:",
            "example": "Nie otwieraj. / Nie spóźnij się."
        },
        {
            "label": "Uprzejmy",
            "color": "blue",
            "text": "<strong>Grzeczna forma</strong> — z poleceniem Proszę:",
            "example": "Proszę usiąść. / Zamknij drzwi, proszę."
        }
    ]
}

{
    "title": "1. Co to jest zdanie rozkazujące?",
    "intro": "Zdanie rozkazujące to zdanie, które wyraża:",
    "items": [
        {
            "label": "Polecenie",
            "title": "Rozkaz",
            "subtitle": "Stop! / Bądź cicho! / Wyjdź teraz!"
        },
        {
            "label": "Prośba",
            "title": "Prośba",
            "subtitle": "Proszę o pomoc. / Podaj proszę sól."
        },
        {
            "label": "Porada",
            "title": "Porada",
            "subtitle": "Weź parasol. / Odpocznij."
        },
        {
            "label": "Instrukcja",
            "title": "Instrukcja",
            "subtitle": "Skręć w lewo. / Naciśnij przycisk."
        },
        {
            "label": "Ostrzeżenie",
            "title": "Ostrzeżenie",
            "subtitle": "Uważaj! / Uważaj!"
        },
        {
            "label": "Zaproszenie",
            "title": "Zaproszenie",
            "subtitle": "Wejdź! / Usiądź."
        }
    ]
}

{
    "title": "2. Konstrukcja zdania rozkazującego",
    "sections": [
        {
            "label": "Struktura podstawowa",
            "color": "emerald",
            "description": "Zdanie rozkazujące zaczyna się od <strong>czasownika w formie podstawowej</strong> (bez to). Temat (ty) jest <strong>nieużywany</strong>.",
            "examples": [
                {
                    "en": "Usiądź.",
                    "ua": "Usiądź."
                },
                {
                    "en": "Otwórz okno.",
                    "ua": "Otwórz okno."
                },
                {
                    "en": "Posłuchaj ja.",
                    "ua": " ja."
                }
            ]
        },
        {
            "label": "Brak podmiotu",
            "color": "sky",
            "description": "W przeciwieństwie do innych zdań, tryb rozkazujący <strong>nie ma podmiotu</strong>. Temat (ty) jest sugerowany.",
            "examples": [
                {
                    "en": "(Ty) Zamknij drzwi.",
                    "ua": "(Ty) Zamknij drzwi."
                },
                {
                    "en": "(Ty) Bądź cicho.",
                    "ua": "(Ty) Bądź cicho."
                },
                {
                    "en": "(Ty) Chodź tutaj.",
                    "ua": "(Ty) Chodź tutaj."
                }
            ],
            "note": "Temat <strong>ty</strong> jest czasami używany dla podkreślenia lub kontrastu: <em>Ty siedzisz tutaj, a ty siedzisz tam.</em>"
        }
    ]
}

{
    "title": "3. Twierdzące",
    "sections": [
        {
            "label": "Struktura: Czasownik + Dopełnienie",
            "color": "emerald",
            "description": "Zdanie twierdzące trybu rozkazującego: <strong>czasownik + dopełnienie</strong>.",
            "examples": [
                {
                    "en": "Otwórz drzwi.",
                    "ua": "Otwórz drzwi."
                },
                {
                    "en": "Przeczytaj tę książkę.",
                    "ua": "Przeczytaj tę książkę."
                },
                {
                    "en": "Wpisz swoje imię i nazwisko.",
                    "ua": "Wpisz swoje imię i nazwisko."
                },
                {
                    "en": "Zadzwoń do mnie jutro.",
                    "ua": "Zadzwoń do mnie jutro."
                }
            ]
        },
        {
            "label": "Bez załącznika",
            "color": "sky",
            "description": "Niektóre zdania rozkazujące składają się tylko z czasowniki.",
            "examples": [
                {
                    "en": "Stop!",
                    "ua": "Stop!"
                },
                {
                    "en": "Czekaj!",
                    "ua": "Czekaj!"
                },
                {
                    "en": "Słuchaj!",
                    "ua": "Słuchaj!"
                },
                {
                    "en": "Uruchom!",
                    "ua": "Uruchom!"
                }
            ]
        },
        {
            "label": "Z czasownikiem BE",
            "color": "amber",
            "description": "Z czasownikiem <strong>be</strong> używamy formy podstawowej.",
            "examples": [
                {
                    "en": "Be uważaj!",
                    "ua": "Uważaj!"
                },
                {
                    "en": "Bądź cicho.",
                    "ua": "Bądź cicho."
                },
                {
                    "en": "Bądź cierpliwy.",
                    "ua": "Bądź cierpliwy."
                },
                {
                    "en": "Bądź włączony czas.",
                    "ua": "Bądź na czas."
                }
            ]
        }
    ]
}

{
    "title": "4. Forma przecząca (ujemna) - nie ",
    "sections": [
        {
            "label": "Struktura: nie + czasownik",
            "color": "rose",
            "description": "Forma przecząca jest tworzona przez <strong>Nie (nie)</strong> przed czasownikiem.",
            "examples": [
                {
                    "en": "Nie otwieraj.",
                    "ua": "Nie otwórz to."
                },
                {
                    "en": "Nie dotykaj tego.",
                    "ua": "Nie dotykaj tego."
                },
                {
                    "en": "Nie zapomnij kluczy.",
                    "ua": "Nie zapomnij kluczy."
                },
                {
                    "en": "Nie martw się.",
                    "ua": "Nie martw się."
                }
            ]
        },
        {
            "label": "Nie martw się...",
            "color": "sky",
            "description": "Z czasownikiem <strong>być</strong>: <strong>Nie bądź</strong> + przymiotnik/rzeczownik.",
            "examples": [
                {
                    "en": "Nie bądź późno.",
                    "ua": "Nie spóźnij się."
                },
                {
                    "en": "Nie bądź głupi.",
                    "ua": "Nie bądź głupi."
                },
                {
                    "en": "Nie bój się.",
                    "ua": "Nie bądź głupi się boisz."
                },
                {
                    "en": "Nie bądź niegrzeczny.",
                    "ua": "Nie bądź niegrzeczny."
                }
            ]
        },
        {
            "label": "Pełna forma",
            "color": "amber",
            "description": "W stylu formalnym użyj pełnej formy <strong>Nie</strong>.",
            "examples": [
                {
                    "en": "Nie wprowadź.",
                    "ua": "Nie wchodź. (na znakach)"
                },
                {
                    "en": "Nie przeszkadzać.",
                    "ua": "Nie przeszkadzać."
                },
                {
                    "en": "Nie palić.",
                    "ua": "Nie palić."
                }
            ],
            "note": "<strong>Zakaz</strong> częściej znajduje się na znakach, instrukcjach i dokumentach urzędowych."
        }
    ]
}

{
    "title": "5. Uprzejme formularze",
    "sections": [
        {
            "label": "Proszę",
            "color": "emerald",
            "description": "Dodanie <strong>proszę</strong> sprawia, że ​​polecenie jest bardziej grzeczne. Może stać na początku lub na końcu.",
            "examples": [
                {
                    "en": "Proszę usiąść.",
                    "ua": "Proszę usiąść."
                },
                {
                    "en": "Zamknij drzwi, proszę.",
                    "ua": "Zamknij drzwi, proszę."
                },
                {
                    "en": "Proszę być cicho.",
                    "ua": "Proszę, bądź cicho."
                },
                {
                    "en": "Pomóż mi, proszę.",
                    "ua": "Pomóż mi, proszę."
                }
            ]
        },
        {
            "label": "Bądźmy dla grupy",
            "color": "sky",
            "description": "<strong>Zróbmy to</strong> (Pozwól nam) jest używane do sugestii, gdy mówca obejmuje siebie.",
            "examples": [
                {
                    "en": "No zaczynamy!",
                    "ua": "Chodźmy!"
                },
                {
                    "en": "Zacznijmy.",
                    "ua": "Zacznijmy."
                },
                {
                    "en": "Zacznijmy lunch.",
                    "ua": "Zjedzmy lunch."
                },
                {
                    "en": "Nie kłóćmy się.",
                    "ua": "Nie kłóćmy się."
                }
            ]
        },
        {
            "label": "Formy alternatywne",
            "color": "amber",
            "description": "Jeszcze bardziej uprzejme sposoby wyrażenia request:",
            "examples": [
                {
                    "en": "Czy mógłbyś otworzyć okno? możesz zamknąć drzwi?",
                    "ua": "Не міг би ти відчинити вікно?"
                },
                {
                    "en": "Would you mind closing the door?",
                    "ua": "Czy możesz zamknąć drzwi?"
                },
                {
                    "en": "Czy możesz mi pomóc?",
                    "ua": "Czy możesz mi pomóc?"
                }
            ],
            "note": "Te formularze są pytaniami, ale służą jako uprzejme prośby."
        }
    ]
}

{
    "title": "6. Stosowanie zdań rozkazujących",
    "sections": [
        {
            "label": "Rozkazy i polecenia",
            "color": "emerald",
            "description": "Bezpośrednie polecenia od rodziców, nauczycieli, szefów itp. Czwartek. róg.",
            "examples": [
                {
                    "en": "Clean your room!",
                    "ua": "Прибери свою кімнату!"
                },
                {
                    "en": "Finish your homework.",
                    "ua": "Закінчи домашнє завдання."
                },
                {
                    "en": "Submit the report by Friday.",
                    "ua": "Здай звіт до пʼятниці."
                }
            ]
        },
        {
            "label": "Інструкції",
            "color": "sky",
            "description": "Покрокові вказівки в рецептах, інструкціях, маршрутах.",
            "examples": [
                {
                    "en": "Mix the flour and eggs.",
                    "ua": "Змішай борошно і яйця."
                },
                {
                    "en": "Turn left at the corner.",
                    "ua": "Skręć w lewo na rogu."
                },
                {
                    "en": "Naciśnij zielony przycisk.",
                    "ua": "Naciśnij zielony przycisk."
                }
            ]
        },
        {
            "label": "Wskazówki i ostrzeżenia",
            "color": "amber",
            "description": "Zalecenia i ostrzeżenia.",
            "examples": [
                {
                    "en": "Weź parasol. Może padać.",
                    "ua": "Weź parasol. Może padać."
                },
                {
                    "en": "Uważaj na lodzie!",
                    "ua": "Uważaj na lodzie!"
                },
                {
                    "en": "Nie jedz za dużo cukru.",
                    "ua": "Nie jedz za dużo cukru."
                }
            ]
        }
    ]
}

{
    "title": "7. Porównanie formularzy",
    "intro": "Forma twierdząca i przecząca:",
    "rows": [
        {
            "en": "Twierdząca",
            "ua": "Twierdząca",
            "note": "Usiądź. / Otwórz. / Bądź cicho."
        },
        {
            "en": "Negatywny",
            "ua": "Negatywny",
            "note": "Nie siedź. / Nie otwieraj tego. / Nie mów głośno."
        },
        {
            "en": "Grzecznie (proszę)",
            "ua": "Grzecznie",
            "note": "Proszę usiąść. / Usiądź, proszę."
        },
        {
            "en": "Usiądźmy (w grupie)",
            "ua": "W imieniu grupy",
            "note": "Usiądźmy. / Nie kłóćmy się."
        }
    ],
    "warning": "📌 Formuła: <strong>Czasownik + Dopełnienie</strong> lub <strong>Nie + Czasownik + Dopełnienie</strong>"
}

{
    "title": "8. Interpunkcja: / Zamknij drzwi. — ton neutralny",
    "intro": "Наказові речення можуть закінчуватися:",
    "rows": [
        {
            "en": "Period (.)",
            "ua": "Крапка",
            "note": "Sit down. / Close the door. — нейтральний тон"
        },
        {
            "en": "Wykrzyknik (!)",
            "ua": "Wykrzyknik",
            "note": "Stop! / Bądź ostrożny! — silne emocje lub pilność"
        }
    ],
    "warning": "⚠️ Użyj wykrzyknika (!) w przypadku pilnych poleceń lub ostrzeżeń."
}

{
    "title": "9. Typowe błędy osób mówiących po ukraińsku",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Dodawanie tematu.",
            "wrong": "Otwórz drzwi!",
            "right": "​​​​ <span class="font-mono">Otwórz drzwi drzwi!</span>"
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Użycie Nie zamiast Nie.",
            "wrong": "Nie dotykaj!",
            "right": "​​​​​​​​​​​ usiądź dół!"
        },
        {
            "label": "Помилка 3",
            "color": "sky",
            "title": "Дієслово з to.",
            "wrong": "To sit down!",
            "right": "​​​​​​​​​​ późno!</span>"
        },
        {
            "label": "Помилка 4",
            "color": "purple",
            "title": "Don't з be — пропуск be.",
            "wrong": "Don't late!",
            "right": "✅ <span class="font-mono">Don't be late!</span>"
        }
    ]
}

{
    "title": "11. Ćwicz",
    "select_title": "Ćwiczenie 1. Wybierz właściwą formę",
    "select_intro": "Wybierz poprawny wariant zdania rozkazującego.",
    "selects": [
        {
            "label": "a) Nie spóźnij się. / b) Nie spóźnij się.",
            "prompt": "Która opcja jest prawidłowa?"
        },
        {
            "label": "a) Zamykasz drzwi! / b) Zamknij drzwi!",
            "prompt": "Która opcja jest poprawna?"
        },
        {
            "label": "a) Nie dotykaj! / b) Nie dotykaj!",
            "prompt": "Która opcja jest poprawna?"
        }
    ],
    "options": [
        "a",
        "b"
    ],
    "input_title": "Ćwiczenie 2. Utwórz formę przeczącą",
    "input_intro": "Zamień zdanie twierdzące na przeczące (za pomocą Nie rób tego).",
    "inputs": [
        {
            "before": "Otwórz okno. →",
            "after": ""
        },
        {
            "before": "Bądź głośno. →",
            "after": ""
        },
        {
            "before": "Zapomnij o kluczach. →",
            "after": ""
        }
    ],
    "rephrase_title": "Ćwiczenie 3. Korekta błędu",
    "rephrase_intro": "Znajdź i popraw błąd w zdaniu rozkazującym.",
    "rephrase": [
        {
            "example_label": "Przykład:",
            "example_original": "Usiądź!",
            "example_target": "Usiądź dół!"
        },
        {
            "original": "1. Aby być cicho!",
            "placeholder": "Napraw błąd"
        },
        {
            "original": "2. Nie spóźnij się na zajęcia!",
            "placeholder": "Popraw błąd"
        }
    ]
}

{
    "title": "Inne strony o podstawach gramatyki",
    "items": [
        {
            "label": "Imperatywy – Zdania rozkazujące",
            "current": true
        },
        {
            "label": "Typy zdań – Rodzaje zdania",
            "current": false
        },
        {
            "label": "Struktura zdania - Struktura zdania S–V–O",
            "current": false
        },
        {
            "label": "Części mowy — części mowy",
            "current": false
        }
    ]
}
